void RoiPointCloudFusionNode::fuse_on_single_image(
  const PointCloudMsgType & input_pointcloud_msg, const Det2dStatus<RoiMsgType> & det2d_status,
  const RoiMsgType & input_rois_msg,
  __attribute__((unused)) PointCloudMsgType & output_pointcloud_msg)
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  if (input_pointcloud_msg.data.empty()) {
    return;
  }

  std::vector<DetectedObjectWithFeature> output_objs;
  std::vector<sensor_msgs::msg::RegionOfInterest> debug_image_rois;
  std::vector<Eigen::Vector2d> debug_image_points;
  // select ROIs for fusion by per-class fusion_enabled_classes flag
  for (const auto & feature_obj : input_rois_msg.feature_objects) {
    const uint8_t roi_label = getHighestProbLabel(feature_obj.object.classification);
    const bool fuse_this_class =
      fusion_enabled_classes_.count(roi_label) && fusion_enabled_classes_.at(roi_label);
    if (!fuse_this_class) {
      continue;
    }
    if (override_class_with_unknown_) {
      auto feature_obj_remap = feature_obj;
      feature_obj_remap.object.classification.front().label = Classification::UNKNOWN;
      output_objs.push_back(feature_obj_remap);
    } else {
      output_objs.push_back(feature_obj);
    }
    debug_image_rois.push_back(feature_obj.feature.roi);
  }

  // check if there is no object to fuse
  if (output_objs.empty()) {
    // publish debug image, which is empty
    if (debugger_) {
      debugger_->image_rois_ = debug_image_rois;
      debugger_->obstacle_points_ = debug_image_points;
      debugger_->publishImage(det2d_status.id, input_rois_msg.header.stamp);
    }
    return;
  }

  geometry_msgs::msg::TransformStamped transform_stamped;
  {
    const auto transform_stamped_optional = getTransformStamped(
      tf_buffer_, input_rois_msg.header.frame_id, input_pointcloud_msg.header.frame_id,
      input_rois_msg.header.stamp);
    if (!transform_stamped_optional) {
      return;
    }
    transform_stamped = transform_stamped_optional.value();
  }
  const int point_step = input_pointcloud_msg.point_step;
  const int x_offset =
    input_pointcloud_msg.fields[pcl::getFieldIndex(input_pointcloud_msg, "x")].offset;
  const int y_offset =
    input_pointcloud_msg.fields[pcl::getFieldIndex(input_pointcloud_msg, "y")].offset;
  const int z_offset =
    input_pointcloud_msg.fields[pcl::getFieldIndex(input_pointcloud_msg, "z")].offset;

  PointCloudMsgType transformed_cloud;
  tf2::doTransform(input_pointcloud_msg, transformed_cloud, transform_stamped);

  std::vector<PointCloudMsgType> clusters;
  clusters.resize(output_objs.size());
  for (auto & cluster : clusters) {
    cluster.point_step = input_pointcloud_msg.point_step;
    cluster.height = input_pointcloud_msg.height;
    cluster.fields = input_pointcloud_msg.fields;
    cluster.data.reserve(input_pointcloud_msg.data.size());
  }
  for (size_t offset = 0; offset < input_pointcloud_msg.data.size(); offset += point_step) {
    const float transformed_x =
      *reinterpret_cast<const float *>(&transformed_cloud.data[offset + x_offset]);
    const float transformed_y =
      *reinterpret_cast<const float *>(&transformed_cloud.data[offset + y_offset]);
    const float transformed_z =
      *reinterpret_cast<const float *>(&transformed_cloud.data[offset + z_offset]);
    if (det2d_status.camera_projector_ptr->isOutsideHorizontalView(transformed_x, transformed_z)) {
      continue;
    }

    Eigen::Vector2d projected_point;
    if (det2d_status.camera_projector_ptr->calcImageProjectedPoint(
          cv::Point3d(transformed_x, transformed_y, transformed_z), projected_point)) {
      for (std::size_t i = 0; i < output_objs.size(); ++i) {
        auto & feature_obj = output_objs.at(i);
        const auto & check_roi = feature_obj.feature.roi;
        auto & cluster = clusters.at(i);

        const double px = projected_point.x();
        const double py = projected_point.y();

        // is not correct to skip fusion and keep a cluster with a partial of points
        if (isPointInsideRoi(check_roi, px, py, roi_scale_factor_)) {
          // append point data to clusters data vector
          cluster.data.insert(
            cluster.data.end(), &input_pointcloud_msg.data[offset],
            &input_pointcloud_msg.data[offset + point_step]);
        }
      }
      if (debugger_) {
        // add all points inside image to debug
        debug_image_points.push_back(projected_point);
      }
    }
  }

  // refine and update output_fused_objects_
  updateOutputFusedObjects(
    output_objs, clusters, input_pointcloud_msg, input_rois_msg.header, tf_buffer_,
    min_cluster_size_, max_cluster_size_, cluster_2d_tolerance_, max_object_size_,
    output_fused_objects_);

  // publish debug image
  if (debugger_) {
    debugger_->image_rois_ = debug_image_rois;
    debugger_->obstacle_points_ = debug_image_points;
    debugger_->publishImage(det2d_status.id, input_rois_msg.header.stamp);
  }
}

std::optional<geometry_msgs::msg::TransformStamped> getTransformStamped(
  const tf2_ros::Buffer & tf_buffer, const std::string & target_frame_id,
  const std::string & source_frame_id, const rclcpp::Time & time)
{
  try {
    geometry_msgs::msg::TransformStamped transform_stamped;
    transform_stamped = tf_buffer.lookupTransform(
      target_frame_id, source_frame_id, time, rclcpp::Duration::from_seconds(0.01));
    return transform_stamped;
  } catch (tf2::TransformException & ex) {
    RCLCPP_WARN_STREAM(rclcpp::get_logger("image_projection_based_fusion"), ex.what());
    return std::nullopt;
  }
}

bool isPointInsideRoi(
  const sensor_msgs::msg::RegionOfInterest & roi, const double camera_point_x,
  const double camera_point_y, const double roi_scale_factor)
{
  const auto scaled_width = static_cast<double>(roi.width) * roi_scale_factor;
  const auto scaled_heigh = static_cast<double>(roi.height) * roi_scale_factor;
  const auto scaled_x_offset = static_cast<double>(roi.x_offset) - (scaled_width - roi.width) / 2.0;
  const auto scaled_y_offset =
    static_cast<double>(roi.y_offset) - (scaled_heigh - roi.height) / 2.0;
  if (
    scaled_x_offset <= camera_point_x && scaled_y_offset <= camera_point_y &&
    scaled_x_offset + scaled_width >= camera_point_x &&
    scaled_y_offset + scaled_heigh >= camera_point_y) {
    return true;
  }
  return false;
}

void updateOutputFusedObjects(
  std::vector<DetectedObjectWithFeature> & output_objs, std::vector<PointCloudMsgType> & clusters,
  const PointCloudMsgType & in_cloud, const std_msgs::msg::Header & in_roi_header,
  const tf2_ros::Buffer & tf_buffer, const int min_cluster_size, const int max_cluster_size,
  const float cluster_2d_tolerance, const double max_object_size,
  std::vector<DetectedObjectWithFeature> & output_fused_objects)
{
  if (output_objs.size() != clusters.size()) {
    return;
  }
  Eigen::Vector3d orig_camera_frame, orig_point_frame;
  Eigen::Affine3d camera2lidar_affine;
  orig_camera_frame << 0.0, 0.0, 0.0;
  const std_msgs::msg::Header & in_cloud_header = in_cloud.header;
  {
    const auto transform_stamped_optional = getTransformStamped(
      tf_buffer, in_cloud_header.frame_id, in_roi_header.frame_id, in_roi_header.stamp);
    if (!transform_stamped_optional) {
      return;
    }
    camera2lidar_affine = transformToEigen(transform_stamped_optional.value().transform);
  }
  orig_point_frame = camera2lidar_affine * orig_camera_frame;
  pcl::PointXYZ camera_orig_point_frame =
    pcl::PointXYZ(orig_point_frame.x(), orig_point_frame.y(), orig_point_frame.z());

  for (std::size_t i = 0; i < output_objs.size(); ++i) {
    auto & cluster = clusters.at(i);
    auto & feature_obj = output_objs.at(i);
    if (
      cluster.data.size() <
      static_cast<std::size_t>(min_cluster_size) * static_cast<std::size_t>(cluster.point_step)) {
      continue;
    }

    // TODO(badai-nguyen): change to interface to select refine criteria like closest, largest
    //  to output refine cluster and centroid
    PointCloudMsgType refine_cluster;
    closest_cluster(
      cluster, cluster_2d_tolerance, min_cluster_size, max_object_size, camera_orig_point_frame,
      refine_cluster);
    if (
      refine_cluster.data.size() <
      static_cast<std::size_t>(min_cluster_size) * static_cast<std::size_t>(cluster.point_step)) {
      continue;
    }
    if (
      refine_cluster.data.size() >
      static_cast<std::size_t>(max_cluster_size) * static_cast<std::size_t>(cluster.point_step)) {
      continue;
    }

    refine_cluster.width = refine_cluster.data.size() / in_cloud.point_step / in_cloud.height;
    refine_cluster.row_step = refine_cluster.data.size() / in_cloud.height;
    refine_cluster.is_bigendian = in_cloud.is_bigendian;
    refine_cluster.is_dense = in_cloud.is_dense;
    refine_cluster.header = in_cloud.header;
    refine_cluster.fields = in_cloud.fields;
    feature_obj.object.kinematics.pose_with_covariance.pose.position = getCentroid(refine_cluster);
    feature_obj.object.existence_probability = 1.0f;
    feature_obj.feature.cluster = refine_cluster;
    output_fused_objects.push_back(feature_obj);
  }
}

std::optional<geometry_msgs::msg::TransformStamped> getTransformStamped(
  const tf2_ros::Buffer & tf_buffer, const std::string & target_frame_id,
  const std::string & source_frame_id, const rclcpp::Time & time)
{
  try {
    geometry_msgs::msg::TransformStamped transform_stamped;
    transform_stamped = tf_buffer.lookupTransform(
      target_frame_id, source_frame_id, time, rclcpp::Duration::from_seconds(0.01));
    return transform_stamped;
  } catch (tf2::TransformException & ex) {
    RCLCPP_WARN_STREAM(rclcpp::get_logger("image_projection_based_fusion"), ex.what());
    return std::nullopt;
  }
}

Eigen::Affine3d transformToEigen(const geometry_msgs::msg::Transform & t)
{
  Eigen::Affine3d a;
  a.matrix() = tf2::transformToEigen(t).matrix();
  return a;
}

void closest_cluster(
  const PointCloudMsgType & cluster, const double cluster_2d_tolerance, const int min_cluster_size,
  const double max_object_size, const pcl::PointXYZ & center, PointCloudMsgType & out_cluster)
{
  // sort point by distance to camera origin

  int x_offset = cluster.fields[pcl::getFieldIndex(cluster, "x")].offset;
  int y_offset = cluster.fields[pcl::getFieldIndex(cluster, "y")].offset;
  int z_offset = cluster.fields[pcl::getFieldIndex(cluster, "z")].offset;
  int point_step = cluster.point_step;
  auto func = [](const PointData & p1, const PointData & p2) { return p1.distance < p2.distance; };
  // Create and sort points_data by distance to camera origin
  std::vector<PointData> points_data;
  for (size_t i = 0; i < cluster.data.size() / point_step; ++i) {
    PointData point_data;
    pcl::PointXYZ point;
    std::memcpy(&point.x, &cluster.data[i * point_step + x_offset], sizeof(float));
    std::memcpy(&point.y, &cluster.data[i * point_step + y_offset], sizeof(float));
    std::memcpy(&point.z, &cluster.data[i * point_step + z_offset], sizeof(float));

    point_data.distance = autoware_utils::calc_distance2d(center, point);
    point_data.orig_index = i;
    point_data.orig_point.x = point.x;
    point_data.orig_point.y = point.y;
    point_data.orig_point.z = point.z;
    points_data.push_back(point_data);
  }
  std::sort(points_data.begin(), points_data.end(), func);
  // extract closest points as output cluster
  out_cluster.data.resize(cluster.data.size());
  out_cluster.point_step = cluster.point_step;
  out_cluster.height = cluster.height;
  size_t out_cluster_size = 0;
  for (size_t i = 0; i < points_data.size(); ++i) {
    if (out_cluster_size == 0) {
      std::memcpy(
        &out_cluster.data[out_cluster_size],
        &cluster.data[points_data.at(i).orig_index * point_step], point_step);
      out_cluster_size += point_step;
      continue;
    }
    double dist_to_closest =
      autoware_utils::calc_distance3d(points_data.at(i).orig_point, points_data.at(0).orig_point);
    if (
      points_data.at(i).distance - points_data.at(i - 1).distance < cluster_2d_tolerance &&
      dist_to_closest < max_object_size) {
      std::memcpy(
        &out_cluster.data[out_cluster_size],
        &cluster.data[points_data.at(i).orig_index * point_step], point_step);
      out_cluster_size += point_step;
      continue;
    }
    if (i >= static_cast<size_t>(min_cluster_size)) {
      out_cluster.data.resize(out_cluster_size);
      return;
    }
    std::memcpy(
      &out_cluster.data[0], &cluster.data[points_data.at(i).orig_index * point_step], point_step);
    out_cluster_size = point_step;
  }
  out_cluster.data.resize(out_cluster_size);
}

double calc_distance2d(const Point1 & point1, const Point2 & point2)
{
  const auto p1 = get_point(point1);
  const auto p2 = get_point(point2);
  return std::hypot(p1.x - p2.x, p1.y - p2.y);
}

double calc_distance3d(const Point1 & point1, const Point2 & point2)
{
  const auto p1 = get_point(point1);
  const auto p2 = get_point(point2);
  // To be replaced by std::hypot(dx, dy, dz) in C++17
  return std::hypot(std::hypot(p1.x - p2.x, p1.y - p2.y), p1.z - p2.z);
}

geometry_msgs::msg::Point getCentroid(const PointCloudMsgType & pointcloud)
{
  geometry_msgs::msg::Point centroid;
  centroid.x = 0.0f;
  centroid.y = 0.0f;
  centroid.z = 0.0f;
  for (sensor_msgs::PointCloud2ConstIterator<float> iter_x(pointcloud, "x"),
       iter_y(pointcloud, "y"), iter_z(pointcloud, "z");
       iter_x != iter_x.end(); ++iter_x, ++iter_y, ++iter_z) {
    centroid.x += *iter_x;
    centroid.y += *iter_y;
    centroid.z += *iter_z;
  }
  const size_t size = pointcloud.width * pointcloud.height;
  centroid.x = centroid.x / static_cast<float>(size);
  centroid.y = centroid.y / static_cast<float>(size);
  centroid.z = centroid.z / static_cast<float>(size);
  return centroid;
}
